import React from "react";
import reactDom from "react-dom";
import './Design.css';

function addGifts(){
    return <>
 <div class="topnav">
<a className="pad" id="">Curtain Gifts</a> 
        <a id="AdminGifts">Gift</a>
        <a id="AdminThemes">Themes</a>
        <a id="AdminOrders">Orders</a>
<a className="padr">Logout</a>
</div> 

<br></br>
<br></br>

<div className="menunav">
    < a className="padr1">Image</a>
    <a>Gift Name</a>
    <a>Price</a>
    <a>Quantity</a>
</div>
showNotes();
<div className="addgift">
    <br/>
<div className="titlebar"> 
        Add Gifts
    </div>
    <div  className="form">
        <br></br>
        <br></br>
        <form >
            <input placeholder = "Enter the Gift Name" type = "text" id = "enterGiftName" name='enterGiftName'></input>
            <br></br>
            <input placeholder = "Enter the Gift Price" type = "number" id =  "enterGiftPrice" name = "enterGiftPrice"></input>
            <br></br>
            <input placeholder = "Enter the Gift Image URL" type = "text" id =  "enterGiftImageUrl" name = "enterGiftImageUrl"></input>
            <br></br>
            <input placeholder = "Enter the Product Quantity" type = "number" id =  "enterGiftQuantity" name = "enterGiftQuantity"></input>
            <br></br>
            <input placeholder = "Enter the Gift Details" type = "text" id =  "enterGiftDetails" name = "enterGiftDetails"></input>
            <br></br>
        </form>
        <div className="center">
        <button  id = "submitButton" type='submit' value="Submit"> ADD </button>
        <br></br>
        </div>
        <br></br>
    </div>
    <br/>
</div>
    </>


}


showNotes();
// If user adds a note, add it to the localStorage
let addBtn = document.getElementById("addBtn");
addBtn.addEventListener("click", function(e) {
	let addTxt = document.getElementById("addTxt");
    let addTitle = document.getElementById("addTxt1");

	let notes = localStorage.getItem("notes");
	let notes1 = localStorage.getItem("notes1");

	if (notes == null) notesObj = [];
	else notesObj = JSON.parse(notes);

	if (notes1 == null) notesObj1 = [];
	else notesObj1 = JSON.parse(notes1);

	notesObj.push(addTxt.value);
	localStorage.setItem("notes", JSON.stringify(notesObj));
	addTxt.value = "";

	notesObj1.push(addTitle.value);
	localStorage.setItem("notes1", JSON.stringify(notesObj1));
	addTitle.value = "";

	showNotes();
});
// Function to show elements from localStorage
function showNotes() {
	let notes = localStorage.getItem("notes");
	if (notes == null) notesObj = [];
	else notesObj = JSON.parse(notes);

	let notes1 = localStorage.getItem("notes1");
	if (notes1 == null) notesObj1 = [];
	else notesObj1 = JSON.parse(notes1);

	let html = "";

	notesObj.forEach(function(element, index ) {
		
		html += `<div class="rectangle1">
				<div> 
					<p > <textarea rows="6" cols="40">
					${notesObj1[index]}
					${element}
						</textarea>
					</p>
                </div>
				<button id="${index}"onclick="deleteNote(this.id)">Delete</button>

		</div> `;
	});
	let notesElm = document.getElementById("notes");

	if (notesObj.length != 0) notesElm.innerHTML = html;
	else
		notesElm.innerHTML = ``;
}

// Function to delete a note
function deleteNote(index) {
	let notes = localStorage.getItem("notes");
let notes1 = localStorage.getItem("notes1");
	if (notes == null) notesObj = [];
	else notesObj = JSON.parse(notes);

	if (notes1 == null) notesObj1 = [];
	else notesObj1 = JSON.parse(notes1);

	notesObj.splice(index, 1);
	notesObj1.splice(index, 1);

	localStorage.setItem("notes",
		JSON.stringify(notesObj));

		localStorage.setItem("notes1",
		JSON.stringify(notesObj));

	showNotes();
}

export default addGifts;
